document.addEventListener('DOMContentLoaded', () => { const navToggle = document.getElementById('navToggle'); const navMobile = document.getElementById('navMobile'); if (navToggle && navMobile) { navToggle.addEventListener('click', () => { navToggle.classList.toggle('open'); navMobile.classList.toggle('open'); }); } const navbar = document.getElementById('navbar'); if (navbar) { const onScroll = () => navbar.classList.toggle('scrolled', window.scrollY > 20); window.addEventListener('scroll', onScroll, { passive: true }); } const fadeUpObserver = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) { entry.target.classList.add('in-view'); fadeUpObserver.unobserve(entry.target); } }); }, { threshold: 0.08, rootMargin: '0px 0px -20px 0px' }); document.querySelectorAll('.animate-fade-up').forEach(el => { fadeUpObserver.observe(el); }); const filterBtns = document.querySelectorAll('.filter-btn'); const templateCards = document.querySelectorAll('.template-card'); if (filterBtns.length > 0 && templateCards.length > 0) { filterBtns.forEach(btn => { btn.addEventListener('click', () => { filterBtns.forEach(b => b.classList.remove('active')); btn.classList.add('active'); const filter = btn.getAttribute('data-filter'); templateCards.forEach(card => { if (filter === 'all' || card.getAttribute('data-category') === filter) { card.style.display = 'block'; card.classList.remove('in-view'); setTimeout(() => card.classList.add('in-view'), 40); } else { card.style.display = 'none'; } }); }); }); } const toggleInput = document.getElementById('billingToggle'); const monthlyLabel = document.getElementById('monthlyLabel'); const annualLabel = document.getElementById('annualLabel'); const priceStarter = document.getElementById('priceStarter'); const pricePro = document.getElementById('pricePro'); if (toggleInput) { toggleInput.addEventListener('change', (e) => { const annual = e.target.checked; monthlyLabel?.classList.toggle('active', !annual); annualLabel?.classList.toggle('active', annual); if (priceStarter) priceStarter.innerHTML = annual ? '$7 <small>/ mo</small>' : '$9 <small>/ mo</small>'; if (pricePro) pricePro.innerHTML = annual ? '$24 <small>/ mo</small>' : '$29 <small>/ mo</small>'; }); } });